        <Box as="ul" listStyle="none" ml={32} p={0}>
          {['Boxes', 'ToolTips', 'Pagination'].map((component, i) => (
            <Box as="li" key={component}>
              <Checkbox
                checked={childrenChecked[i]}
                htmlFor={`nested-child-${i}`}
                label={component}
                name={`nested-child-${i}`}
                onChange={toggleChild(i)}
              />
            </Box>
          ))}
        </Box>
      </Box>
    );
  };

  return <NestedCheckboxesComponent />;
};

