export const parameters = {
  title: 'FocusTrap',
  subtitle:
    "Used for modal and dialog experiences that use `Overlay`. This component controls focus management behavior when we need to limit focus to a single area of the page for some amount of time. It doesn't need to be a modal or overlay, and can instead be controlled with the `active` prop.",
  status: 'current',
  source: {
    repo: 'gamut',
    githubLink:
