      </FlexBox>
      {isVisible && (
        <Alert
          closeButtonProps={{
            tip: 'Wow, a left-aligned tooltip!',
            ref: closeButtonRef,
            tipAlignment: 'left-center' as const,
          }}
          type="feature"
          onClose={() => setIsVisible(false)}
        >
          <FlexBox flexDirection="column" gap={16}>
            <Text>Expand this Alert to see focus controls</Text>
            <FlexBox gap={8}>
              <FillButton
                disabled={isDisabled}
                onClick={handleFocusCloseButton}
              >
                Focus Close Button
              </FillButton>
              <FillButton onClick={() => setIsDisabled(!isDisabled)}>
                {isDisabled ? 'Enable' : 'Disable'} Focus Button
              </FillButton>
            </FlexBox>
          </FlexBox>
        </Alert>
      )}
    </>
  );
};

