const RowMenu: React.FC<{ rowName: string }> = ({ rowName }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const menuButtonRef = useRef<HTMLDivElement>(null);

  const handleClose = () => {
    setIsOpen(false);
  };

  const handleOpenModal = () => {
    setIsOpen(false);
    setIsModalOpen(true);
  };

  return (
    <Box display="inline-block" p={8} ref={menuButtonRef}>
      <IconButton
        icon={MiniKebabMenuIcon}
        tip="Show options"
        tipProps={{
          alignment: 'left-center',
          placement: 'floating',
        }}
        variant="secondary"
        onClick={() => setIsOpen(!isOpen)}
      />

      <PopoverContainer
        alignment="bottom-left"
        allowPageInteraction
        closeOnViewportExit
        isOpen={isOpen}
        offset={0}
        targetRef={menuButtonRef}
        onRequestClose={handleClose}
      >
        <Menu borderRadius="md" spacing="normal" variant="popover">
          <MenuItem onClick={handleClose}>
            <Text truncate="ellipsis" truncateLines={1}>
              Edit {rowName}
            </Text>
          </MenuItem>
          <MenuItem onClick={handleClose}>
            <Text truncate="ellipsis" truncateLines={1}>
              Delete {rowName}
            </Text>
          </MenuItem>
          <MenuItem onClick={handleOpenModal}>
            <Text truncate="ellipsis" truncateLines={1}>
              Clone {rowName}
            </Text>
          </MenuItem>
        </Menu>
      </PopoverContainer>

      <Dialog
        cancelCta={{
          children: 'Cancel',
          onClick: () => setIsModalOpen(false),
        }}
        confirmCta={{
          children: 'Clone',
          onClick: () => {
            // Handle clone action here
            setIsModalOpen(false);
          },
        }}
        isOpen={isModalOpen}
        size="small"
        title={`Clone ${rowName}`}
        onRequestClose={() => setIsModalOpen(false)}
      >
        Are you sure you want to clone{' '}
        <Text as="span" fontWeight="bold">
          {rowName}{' '}
        </Text>
        ? This action cannot be undone.
      </Dialog>
    </Box>
  );
};

