const meta: Meta<typeof GridForm> = {
  component: GridForm,
  args: {
    onSubmit: (values) => {
      action('Form Submitted')(values);
      // eslint-disable-next-line no-console
      console.log('Form Submitted', values);
    },
    submit: {
      contents: 'Submit',
      size: 4,
      position: 'left',
    },
    hideRequiredText: true,
  },
};

export default meta;
